<template>
  <div class="main-all" >
    <div class="logo"><img src="../assets/logo.svg" alt=""></div>
    <div id="nav-icon3">
      <span></span>
      <span></span>
      <span></span>
      <span></span>
    </div>
    <div class="nav">
      <li>HOME</li>
      <li>ABOUT</li>
      <li>INFO</li>
      <li>AUDIO</li>
      <li>CONTACT</li>
    </div>
    <div class="social">
     <a href=""><li style="z-index: 2"><i class="fa fa-facebook-f"></i> <p>1230 likes</p></li></a> 
      <a href="https://www.youtube.com/user/TheCatch13777/featured"><li style="z-index: 3"><i class="fa fa-youtube-play"></i> <p>1230 likes</p></li></a>
     <a href=""><li style="z-index: 4"><i class="fa fa-twitter"></i> <p>1230 likes</p></li></a>
      <a href=""><li style="z-index: 5"><i class="fa fa-instagram"></i> <p>1230 likes</p></li></a>
    </div>
    <div class="intro">
    <h1>
      <a href="" class="typewrite" data-period="2000" data-type='[ "Iglesia de Cristo","Church of Christ", "כנסיית המשיח", "基督教會",  "كنيسة المسيح", "Kirche Christi", "εκκλησία του", "キリスト教会", "церковь Христа" ]'>
        <span class="wrap"></span>
      </a>
    </h1> 
      <h2 id="verse"></h2>
    </div>
    <div class="info" @click="toggle()">
      <div class="close-info"><i class="fa fa-times-circle-o"></i></div>
      <div class="info-icon"><i class="fa fa-info"></i></div>
      <div class="info-main">
        <div class="contact">
             <div>
              <h1>Hello</h1>
            </div>
          </div>
        <div class="map"> 
          <div>
              <h1>Hello</h1>
            </div></div>
      </div>
    </div>
    <welcome/>
    <evan/>
    <topic/>
    <plan/>
    <study/>
    <youtube/>
    <groups/>
  </div>
</template>

<script>
import $ from 'jquery'
import welcome from './Welcome.vue'
import evan from './Evangelism.vue'
import topic from './Topics.vue'
import plan from './Salvacion.vue'
import study from './Study.vue'
import youtube from './Youtube.vue'
import groups from './Groups.vue'
import axios from 'axios'

export default {
  name: 'HelloWorld',
  components: {
    welcome,
    evan,
    topic,
    plan,
    study,
    youtube,
    groups
  },
  data () {
    return {
    }
  },
  methods: {
    toggle(){
      $('.info').toggleClass('expand');
      console.log($('.info'))
    },
     getCarousel(){
            var verses = [];
            for(var i=0; i < 5; i++) {
              axios.get('https://cors-anywhere.herokuapp.com/https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname).then(response => {
                var verse = response.data.slice(35).split('</div>')[0]
                  var script = response.data.split("target=\"_blank\">").pop();
                  verses.push({verse: verse, script: script.substring(0, script.indexOf("</a>"))})                 

                      $('#verse').html(verses[0].verse + " " + "<br> <strong style='color:rgba(52, 146, 153, .7)!important'>" +  verses[0].script + "</strong>")

                })
            }
            var curindex = 0;

            setInterval(()=> {
              ++curindex;
                  if(curindex >= verses.length) {
                    curindex = 0;
                  }
            var result = verses.filter( (verse, index) =>  curindex == index)

  //  transform: translate(-50%, -50%)
              $('#verse').animate({opacity: 0}, 500,function() {
                    $(this).html(result[0].verse + " " + "<br> <strong style='color:rgba(52, 146, 153, .7)!important'>" + result[0].script + "</strong>").animate(
                      { opacity: 1}
                      );
                });
            }, 7000)
   } 
  },
  mounted(){
    this.getCarousel()

    $(document).ready(function(){
        $('#nav-icon1,#nav-icon2,#nav-icon3,#nav-icon4').click(function(){
          $(this).toggleClass('open');
          $('.nav').toggleClass('show');

          	$('#fullpage').fullpage({
                //options here
                autoScrolling:true,
                scrollHorizontally: true
              });

              //methods
              $.fn.fullpage.setAllowScrolling(false);
        });

    // $('.info').click(function(){
    //   $(this).addClass('expand');
    // })
      
});

    var TxtType = function(el, toRotate, period) {
        this.toRotate = toRotate;
        this.el = el;
        this.loopNum = 0;
        this.period = parseInt(period, 10) || 2000;
        this.txt = '';
        this.tick();
        this.isDeleting = false;
    };

    TxtType.prototype.tick = function() {
        var i = this.loopNum % this.toRotate.length;
        var fullTxt = this.toRotate[i];

        if (this.isDeleting) {
        this.txt = fullTxt.substring(0, this.txt.length - 2);
        } else {
        this.txt = fullTxt.substring(0, this.txt.length + 2);
        }

        this.el.innerHTML = '<span class="wrap">'+this.txt+'</span>';

        var that = this;
        var delta = 200 - Math.random() * 100;

        if (this.isDeleting) { delta /= 2; }

        if (!this.isDeleting && this.txt === fullTxt) {
        delta = this.period;
        this.isDeleting = true;
        } else if (this.isDeleting && this.txt === '') {
        this.isDeleting = false;
        this.loopNum++;
        delta = 500;
        }

        setTimeout(function() {
        that.tick();
        }, delta);
    };

    window.onload = function() {
        var elements = document.getElementsByClassName('typewrite');
        for (var i=0; i<elements.length; i++) {
            var toRotate = elements[i].getAttribute('data-type');
            var period = elements[i].getAttribute('data-period');
            if (toRotate) {
              new TxtType(elements[i], JSON.parse(toRotate), period);
            }
        }
        // INJECT CSS
        var css = document.createElement("style");
        css.type = "text/css";
        css.innerHTML = ".typewrite > .wrap { border-right: 0.08em solid #fff}";
        document.body.appendChild(css);
    };
  }
}
</script>

