<template>
    <div class="plan">
        <div class="back-text">PLAN DE SALVACION</div>
        <div class="video">
            <video autoplay muted loop id="myVideo">
                <source src="../assets/World.mp4" type="video/mp4">
                Your browser does not support HTML5 video.
                </video>
        </div>
        <div class="back"></div>

        <div class="steps">
            <div class="step s1">
                <div class="step-box">
                    <h1>01 CREER</h1>
                    <p>DEBES OÍR LA VERDADERA PALABRA DE DIOS "Así que la fe viene por el oír y el oir por la palabra de Dios". (Romanos 10:17)</p>
                </div>
            </div>
            <div class="step s2">
                <div class="step-box">
                    <h1>02</h1>
                </div>
            </div>
            <div class="step s3">
                <div class="step-box">
                    <h1>03</h1>
                </div>
            </div>
            <div class="step s4">
                <div class="step-box">
                    <h1>04</h1>
                </div>
            </div>
            <div class="step s5">
                <div class="step-box">
                    <h1>05</h1>
                </div>
            </div>
            <div class="step s6">
                <div class="step-box">
                    <h1>06</h1>
                </div>
            </div>
        </div>
        <!-- <div class="pane">
            <div class="main-pane"></div>
        </div> -->

    </div>
</template>

<script>
export default {
mounted(){
    var vid = document.getElementById("myVideo");

    function setPlaySpeed() { 
            vid.playbackRate = 0.5;
        } 

   setPlaySpeed()
}
}
</script>

<style lang="scss" scoped>
.plan {
    height: 92vh;
    width: 100%;
    position: relative;
    overflow: hidden;
    z-index: 9;

}
.back-text {
    position: absolute;
    color:white;
    font-size: 8vmin;
    opacity: .3;
    z-index: 1;
    left: 50%;
    top: 50%;
    margin-right: -50%;
    transform: translate(-50%, -50%)

}
    .back {
        height: 93vh;
        width: 100%;
        background-image: url("../assets/space.jpg");
        // background-attachment : fixed;
        background-size: cover;
        opacity: .4;
        top: 0;
        z-index: 1;
        position: absolute;

    }
    .video {
        position: absolute;
        width: 100%;
        height: 100%;
        // z-index: 2;
        background: black;
        // left: -160px;

    }
    #myVideo {
        position: absolute;
        height: 100%;
        width: 100%;
        left: 0;
        opacity: .6;
    }
.steps {
    position: relative;
    width: 40%;
    height: 100%;
    z-index: 3;
    left: 10%;
    // background: red;
    .step {
        position: relative;
        height: 7%;
        width: 300px;
        top: 8vh;
        margin-left: 10vw;
        border-bottom: white solid 2px;
        transition: all .6s ease-in-out;
        padding: 20px;
    .step-box {
        height: 100%;
        width: 100%;
        h1 {
            color: white;
        }
        p {
            color:white;
            opacity: 0;
        }
    }
    &:hover {
        // left: 100px;
        background: url("../assets/glow.png");
        background-size: cover;
        height: 150px;
        width: 100%;
        transition: all .6s ease-in-out;
        p {
            font-size: 2vmin;
            position: relative;
            top: 20px;
            transition: all .6s ease-in-out;
            opacity: 1;
        }
        
    }
    }
    // .step {
    //     left: 25%;
    // }
    .s1 {
        position: relative;
        left: 20%;
    }
    .s2 {
        position: relative;
        left: 30%;
    }
    .s3 {
        position: relative;
        left: 40%;
    }
    .s4 {
        position: relative;
        left: 50%;
    }
    .s5 {
        position: relative;
        left: 60%;
    }
    .s6 {
        position: relative;
        left: 70%;
    }
}


    .pane {
        position: absolute;
        right:0;
        top: 0;
        // background: white;
        height: 100%;
        width: 60%;
        .main-pane {
            position: relative;
            background: rgb(56, 56, 56);
            height: 80%;
             width: 80%;
            left: 50%;
            top: 50%;
            margin-right: -50%;
            transform: translate(-50%, -50%)
        }
    }

</style>



