<template>
    <div class="topic">
        <div class="main">
            <div class="main-head">
            <div class="main-content l">
                <h2>Himnos</h2>
                <p>description</p>
                <img class="lun-img" src="../assets/music.jpg" alt="">
            </div>
            <div class="main-content m">
                <h2>Como EL</h2>
                <p>description</p>
                <img class="mier-img" src="../assets/comoel.jpg" alt="">
            </div>
            <div class="main-content d">
                <h2>Oh Corintios</h2>
                <p>description</p>
                <img class="dom-img" src="../assets/corintios.jpg" alt="">
            </div>
            <div class="main-content d2">
                <h2>Apocalipsis</h2>
                <p>description</p>
                <img class="dom2-img" src="../assets/apocalipsis.jpg" alt="">
            </div>
            </div>
            <div class="section lun">
                <div>
                    <h3>Lunes</h3>
                    <h1>7 - 8 PM <br> <a href="https://www.google.com/maps/place/Church+of+Christ/@42.038945,-88.3042241,15z/data=!4m5!3m4!1s0x0:0x46f7a2a8a950e784!8m2!3d42.038945!4d-88.3042241" target="blank"><i class="fa fa-map-marker"></i></a></h1>
                </div>
            </div>
              <div class="section mier">
                <div>
                    <h3>Miercoles</h3>
                    <h1>7 - 8 PM <br> <a href="https://www.google.com/maps/place/Church+of+Christ/@42.038945,-88.3042241,15z/data=!4m5!3m4!1s0x0:0x46f7a2a8a950e784!8m2!3d42.038945!4d-88.3042241" target="blank"><i class="fa fa-map-marker"></i></a></h1>
                </div>
            </div>
              <div class="section dom">
                <div>
                    <h3>Domingo AM</h3>
                    <h1>9:30 - 11 AM <br> <a href="https://www.google.com/maps/place/Church+of+Christ/@42.038945,-88.3042241,15z/data=!4m5!3m4!1s0x0:0x46f7a2a8a950e784!8m2!3d42.038945!4d-88.3042241" target="blank"><i class="fa fa-map-marker"></i></a></h1>
                </div>
            </div>
              <div class="section dom2">
                <div>
                    <h3>Domingo PM</h3>
                    <h1>3 - 4 PM <br> <a href="https://www.google.com/maps/place/Church+of+Christ/@42.038945,-88.3042241,15z/data=!4m5!3m4!1s0x0:0x46f7a2a8a950e784!8m2!3d42.038945!4d-88.3042241" target="blank"><i class="fa fa-map-marker"></i></a></h1>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import $ from 'jquery'

export default {
mounted() {
    $('.lun').hover(function(){
        $('.l').toggleClass('show')
    })
        $('.mier').hover(function(){
        $('.m').toggleClass('show')
    })
        $('.dom').hover(function(){
        $('.d').toggleClass('show')
    })
        $('.dom2').hover(function(){
        $('.d2').toggleClass('show')
    })
}
}
</script>

<style lang="scss" scoped>
    .topic {
        height: 100vh;
        width: 100%;
    .main {
    width: 100%;
    height: 100%;
    background: linear-gradient(to bottom, rgb(60, 60, 60) 0%,rgba(14, 14, 14, 0.25) 100%);
    // background: black;
    .main-head {
        position: absolute;
        height: 100vh;
        width: 100%;

        .main-content {
            color: white;
            h2, p {
                transform: translateX(400px)
            }
           h2 {
               position: absolute;
               opacity: 0;
               z-index: 1;
               bottom: 10%;
               right: 20%;
               font-size: 10vmin;
           }
           p{
            z-index: 1;
            opacity: 0;
            position: absolute;
            bottom: 10%;
            right: 20%;
            font-size: 3vmin;
           }
 
        }
    }
           img {
            position: absolute;
            opacity: 0;
            top:0;
            left: 0;
            width: 100%;
            height: 100vh;
            transition: all 1s ease-in-out;
        }
    .show {
        img {
            opacity: .5;
        }
         h2, p {
             transition: all .7s cubic-bezier(0.175, 0.885, 0.32, 1.275);
             transform: translateX(0px)!important;
              opacity: .7!important;
              z-index: 99;
           }
  
    }
        .section {
            z-index: 3;
            position: relative;
            float: left;
            width: 23%;
            margin: 1%;
            height: 40%;
            top: 30%;
            filter: grayscale(.8);
            display: flex;
            justify-content: center;
            align-items: center;
            transition: all .4s ease;
            div {
                width: 100%;
                height: 50%;
                padding: 80px;
                position: relative;
                text-align: center;
                color: white;
                cursor: pointer;
                a {
                    color: white;
                }
                h1 {
                transition: all .5s ease-in-out;
                    font-size: 4vmin;
                    opacity: 0;

                    i {
                        font-size: 100px;
                        top: 50px;
                        position: relative;
                         transition: all .2s ease-in-out;
                    }
                    i:hover {
                        transform: scale(1.3)
                    }
                }
             
                h3 {
                transition: all .5s ease-in-out;
                    font-size: 50px;
                }
            
            }
        &:hover {
            h1 {
                opacity: 1;
                 transform: translateY(-200px)
            }
            h3 {
                opacity: 0;
                transform: translateY(-300px)
            }
            background: rgba(0, 0, 0, 0);
            transition: all 2s ease;
        }
        }

        .lun {
            // background: rgba(61, 61, 61, 0.2);
            background: url('../assets/music.jpg');
            background-size: 150%;
        }
        .mier {
            background: rgba(61, 61, 61, 0.3);
            background: url('../assets/comoel.jpg');
            background-size: 150%;
        }
        .dom {
            background: rgba(61, 61, 61, 0.4);
            background: url('../assets/corintios.jpg');
            background-size: 150%;
        }
        .dom2 {
            background: rgba(61, 61, 61, 0.5);
            background: url('../assets/apocalipsis.jpg');
            background-size: 200%;
        }
    }
    }

</style>



