<template>
    <div class="youtube">
        <div class="back"></div>
        <div class="video">
            <iframe src="http://www.youtube.com/embed/?listType=user_uploads&list=TheCatch13777&rel=0&showinfo=0&controls=1&theme=light" allowfullscreen ></iframe>                   
        </div>
        <div class="more">
            <button>
                <i class="fa fa-youtube-play"></i>
                <a href="https://www.youtube.com/user/TheCatch13777/featured" target="blank">MAS VIDEOS!</a>
            </button>
       
        </div>
    </div>
</template>

<script>
import $ from 'jquery'

export default {
    data(){
        return {
            items: [1,2,3,4,5,6],
            iclicked: '',
            showing: false
        }
    },
    mounted(){
        // $('.playlist').click(function() {
        //     $(this).toggleClass('expand');
        // })
    }

}
</script>

<style lang="scss" scoped>
    .youtube {
        height: 700px;
        width: 100%;
        position: relative;
        overflow: hidden;
        .video {
            width: 100%;
            height: 100%;
            display: flex;
            justify-content: center;
            align-items: center;
            iframe {
            border: none;
            width: 100vh;
            height: 590px;
            }
        }
        .more {
            position: absolute;
             left: 100%;
            // right: 300%;
            top: 50%;
            margin-right: -50%;
            transform: translate(-50%, -50%);
            button {
                background: rgba(45, 92, 95, 0.781);
                border: none;
                // left: 20px;
                // border-radius: 50%;
                overflow: hidden;
                box-shadow: -5px 5px 15px 0px rgba(0,0,0,0.6);
                height: 100px;
                width: 100px;
                transition: all ease-in-out .3s;
                i {
                    font-size: 45px;
                    color: white;
                    opacity: 1;

                }
                a {
                    position: absolute;
                    color: white;
                    opacity: 0;
                    font-size: 20px;
                    cursor: pointer;
                }
            }
            button:hover {
                transform: scale(2);
                border-radius: 0%;
                top: -50px;
                padding-right: 300px;
                right:80%;
                position: absolute;
                i {
                       margin-left: 50px; 
                }
                a {
                    opacity: 1;
                    top: 40px;
                    left: 120px;

                }
            
            }
        }

        .back {
            position: absolute;
            height: 100%;
            width: 100%;
            opacity: .2;
            background-image: url("../assets/pattern2.jpg");
            background-attachment : fixed;
            background-size: cover;
            top: 0;
            left: 0;
        }
        div {
            position: relative;
            color:white;
            width: 33.3%;
            height: auto;
            float: left;
            // background: white;
            // padding: 20px;
            // margin: 10px;
            // padding: 30px;

            .playlist  {
                background: red;
                width: 90%;
                position: relative;
                z-index: 0;
                margin: 30px;
                height: 250px;
                cursor: pointer;
            }
        }
            .showing {
                background: blue;
                width: 100%;
                position: absolute;
                height: 100%;
                top: 0;
                left: 0;
                z-index: 1;
            }
    }


</style>



