import Vue from 'vue'
import Router from 'vue-router'
import HelloWorld from '@/components/HelloWorld'
import Home from '@/components/Home'
import test from '@/components/test'
import study from '@/components/Study1'
import serie from '@/components/Series'
import team from '@/components/Team'
import group from '@/components/Groups'
import events from '@/components/Calendario'
import plan from '@/components/Plan'
import rdj from '@/components/RDJ'
import mision from '@/components/Mission'
import member from '@/components/Member'
import dash from '@/components/Dashboard'

Vue.use(Router)

export default new Router({
  routes: [
    {
      path: '/',
      name: 'home',
      component: Home
    },
    {
      path: '/s',
      name: 'study',
      component: study,
      props: true,
    },
    {
      path: '/s/:serie',
      name: 'serie',
      component: serie,
      props: true
    },
    {
      path:'/s/:serie/:track',
      props: true,
      component: serie
    },
    {
      path: '/equipo',
      name: 'team',
      component: team,
      props: true
    },
    {
      path: '/eventos',
      name: 'eventos',
      component: events,
      props: true
    },
    {
      path: '/grupos',
      name: 'grupos',
      component: group,
      props: true
    },
        {
      path: '/salvacion',
      name: 'plan',
      component: plan,
      props: true
    },
    {
      path: '/RNDJ',
      name: 'rdj',
      component: rdj,
      props: true
    },
    {
      path: '/mision',
      name: 'mission',
      component: mision,
      props: true
    },
    {
      path: '/miembros',
      name: 'member',
      component: member,
      props: true
    },
    {
      path: '/dashboard/:email',
      name: 'dash',
      component: dash,
      meta:{requiresAuth: true},
      props: true
    },
  ],
  mode: 'history'
})



