<template>
<div class="study">
    <div class="intro" data-aos="zoom-out" data-aos-duration="1000">
        <h1 class="fade-in">{{title.replace(/-/g, " ")}}</h1>
        <p class="fade-in-o">{{seriesAll[3]}}</p>
        <img v-parallax.modifier="0.3" :src="seriesAll[4]" alt="">
        <div class="tab">
            <h2>Serie | {{title.replace(/-/g, " ")}}</h2>
            <h2>Sermones | {{series.length}}</h2>
        </div>
    </div>
    <div class="search">
            <i class="fa fa-search"></i>
            <input class="bar" type="text" v-model="search" name="search">
    </div>
    <div class="series">
    <!-- <div class="overlay"></div> -->
            <div class="sec">
          
               <li class="item" v-for="(audio, index) in searchList" :key="index" :id="audio.url" :value="audio.url"  @click="playAudio(audio, index);"> 
                    <div class="sub" :class="{ playing : audio.isActive}" >
                        <h2 class="truncate para" >{{audio.name.replace(/.mp3/g, "")}}</h2>
                        <p>Ricardo Barrera | DATE</p>
                    </div>
                    <div class="icon"> 
                             <!--<i v-if ="!audio.isActive"  class="fa fa-play" @click="playAudio(audio, index);" ></i> -->
                            <!-- <i v-if ="audio.isActive"  class="fa fa-pause" @click="pauseAudio(audio, index)"></i> -->
                            <a :href="Audio.src" download><i class="fa fa-cloud-download" style="padding: 10px 10px;"></i></a>
                            <i class="fa fa-share-alt"></i>
                    </div>
                </li>  
            </div>
        </div>

        <div class="controls">
            <!-- <img src="../assets/overlay.png" alt="">              -->
           <!-- <div class="seek"><input id="seekslider" type="range" min="0" max="100" :value="value" step="1" @input="seeking"></div>  -->
            <div class="seek"><input id="seekslider" type="range" min="0" max="100" :value="value" step="1" @input="seeking"></div>
                <div id="timebox-start"><span @change="audioLoaded === false">{{time}}</span></div>
                <div id="timebox-end"><span @change="audioLoaded === false">{{endtime}}</span></div>
            <div class="main">
                <i class="fa fa-backward" @click="prevTrack()" aria-hidden="true"></i>
                <i class="fa fa-pause" @click="pauseAudio(audio)" v-if="playing === true"  aria-hidden="true"></i>
                <i class="fa fa-play" @click="resumeAudio()" v-else  aria-hidden="true"></i>
                <i class="fa fa-forward"   @click="nextTrack()" aria-hidden="true"></i>
            </div>
        </div>
        <div class="foot">
            <foot/>
        </div>
</div>
</template>

<script>
import $ from 'jquery'
import axios from 'axios'
import firebase from 'firebase'
import {realDB} from  '../firebase/firebase'
import {s3} from  '../aws/aws-audio';
import foot from './Footer.vue'

export default {
    data(){
        return {
            pause: false,
            series:[],
            seriesAll: [],
            search: '',
            title: '',
            des: '',
            audioLoaded: true,
            playing: false,
            mute:false,
            currentSerieSel: [],
            Audio:'',
            const: {
                amz: "https://s3.us-east-2.amazonaws.com/idcaudio/"
            },
            audio: {
                index: '',
                url:'',
                currentSerie: '',
                // currSerieImg: require('../../assets/img/series/audio-cover.png'),
                currentDes: 'Descripcion de Serie',
                serieLength: '',
                currentTrack: "Escoje un Audio...",
                des: ''
            },
            time: "00:00",
            endtime: "00:00",
            value: "0",
            volume: '100'
        }
    }, 
    components:{
    foot
},
    methods: {

          newAudio(){

            this.Audio = new Audio();
             this.Audio.addEventListener("timeupdate", this.seekUpdate);

      },
      playAudio(track , index){
        this.series.forEach(val => {
            val.isActive = false;
        })
        this.audioLoaded = true; 
        track.isActive = true;
          
            this.Audio.src = this.const.amz + track.url;
            this.playing = true;
            this.Audio.play();

            this.$router.push('/s/'+ this.title +'/'+ track.name);

      },
      pauseAudio(track , index){
            track.isActive = false;
            this.playing = false;
            this.Audio.pause();
      },
      resumeAudio(){
             this.playing = true;
            this.Audio.play();
      },
      ////TRY OUT PREV AND NEXT BUTTONS WHEN DATA ADDED!
      nextTrack(){

          
        
        var trackUrl = document.getElementById(this.audio.url);
            var trackname = $(trackUrl).next().attr('value')

             if(trackname === undefined) {

                    this.Audio.src = this.const.amz + $(trackUrl).attr('value')
                    this.audio.currentTrack = $(trackUrl).children('p').text()
                    this.audio.currentTrack = this.audio.currentTrack.substring(this.audio.currentTrack.indexOf("|") + 1);

                    this.Audio.play();

                    this.audio.url = $(trackUrl).attr('value');
                
            } else {
            this.Audio.src = this.const.amz + $(trackUrl).next().attr('value')
            this.audio.currentTrack = $(trackUrl).next().children('p').text()
            this.audio.currentTrack = this.audio.currentTrack.substring(this.audio.currentTrack.indexOf("|") + 1);
            this.Audio.play();

            this.audio.url = $(trackUrl).next().attr('value');
            }

           
        
    
      },
      prevTrack(){
        
        var trackUrl = document.getElementById(this.audio.url);
          var trackname = $(trackUrl).prev().attr('value')

           if(trackname === undefined) { 
                    this.Audio.src = this.const.amz + $(trackUrl).attr('value')
                    this.audio.currentTrack = $(trackUrl).children('p').text()
                    this.audio.currentTrack = this.audio.currentTrack.substring(this.audio.currentTrack.indexOf("|") + 1);
                    this.Audio.play();
                    this.audio.url = $(trackUrl).attr('value');
           
           } else {
            this.Audio.src = this.const.amz + $(trackUrl).prev().attr('value')
            this.audio.currentTrack = $(trackUrl).prev().children('p').text()
            this.audio.currentTrack = this.audio.currentTrack.substring(this.audio.currentTrack.indexOf("|") + 1);
            this.Audio.play();

            this.audio.url = $(trackUrl).prev().attr('value'); 
           }

            
        
      },
      seekUpdate(){
           
        var nt = this.Audio.currentTime * (100 / this.Audio.duration)
      
       this.value = nt;
      
       var curhrs = Math.floor(this.Audio.currentTime / 3600);
       var curmins = Math.floor(this.Audio.currentTime / 60);
       var cursecs = Math.floor(this.Audio.currentTime - curmins * 60);

       var durhrs = Math.floor(this.Audio.duration / 3600);
       var durmins = Math.floor(this.Audio.duration / 60);
       var dursecs = Math.floor(this.Audio.duration - durmins * 60);

         if(durhrs > 0){
            durmins = durmins % 60;
            curmins = curmins % 60;
        }
       
        if(cursecs < 10){ cursecs = "0" + cursecs; }
        if(curmins < 10){ curmins = "0"+ curmins; }
      

        if(dursecs < 10){ dursecs = "0"+ dursecs; }
        if(durmins < 10){ durmins = "0"+ durmins; }

        
        if(durhrs == 0){ 
              this.time = curmins+":"+cursecs;
               this.endtime = durmins+":"+dursecs;

        } else {
            this.time = curhrs+":"+curmins+":"+cursecs;
            this.endtime = durhrs+":"+durmins+":"+dursecs;
        }

      },
      seeking(event){
            
            var seekto = this.Audio.duration * (event.target.value / 100);  

            this.Audio.currentTime = seekto;     
        },
        volumeChange(event){

            this.Audio.volume = event.target.value / 100;
            this.volume = event.target.value;

        }, 
         getlist(arr){
             
            for(var prop in arr[0]){

                arr[0][prop].isActive = false;

                this.series.push(arr[0][prop])
            }

            console.log(arr[0])
        },

       
    },
        computed:{
            searchList: function(){
                return this.series.filter((serie) => {
                    return serie.name.toLowerCase().match(this.search);
                })
            },
        },
    created(){
        
        var arr = [];
              realDB.ref('series').child(this.$route.params.serie).on(('value'), function(snapshot){
                snapshot.forEach(function(child){
                    arr.push(child.val())
                })
               
            })

          this.seriesAll = arr
          this.getlist(arr)
    },  
    mounted(){
            this.title = this.$route.params.serie;
        
   

    $('.fa-search').click(function(){
        $('.search').toggleClass('show');
    })

       this.newAudio()

    
}

}
</script>

<style scoped lang="scss">

.study {
    background: #fff;
    // height: 100%;
    position: relative;
    z-index: 1;
}

.search {
    height: 70px;
     input {
            position: relative;
            opacity: 0;
            font-size: 25px;
            // color: white;
            font-family: 'Montserrat', sans-serif;
            font-weight: 200;
            top: 10px;
            left:40px;
            width: 93%;
            background: transparent;
            border: none;
            border-bottom: solid #8cdacf 2px;
            transition: all .3s ease-in-out;
            
        }
        input[type=text] {
            color: rgb(78, 138, 143);
            font-weight: 500;
        }
          i {
                top: 10px;
                color: #4f4f4f;
                font-size: 40px;
                position: relative;
                left: 50%;
                z-index: 3;
                transition: all .5s ease-in-out;
                cursor: pointer;
                
        }
}
 .show {
     input {
         opacity: 1;
         transition-delay: .4s;
     }
     i {
         left: 30px;
     }
 }       
 .tab {
     display: inline-flex;
     h2 {
         position: relative!important;
         width: 200px;
     }
 }

   #timebox-start {
        position: absolute;
        width: auto;
        left: 0;
        top: -35px;
        color: #66a59d;
        background: black;
        font-size: 30px;
        
        // left:45%!important;
         margin-left: 0;
         text-align: center;
         margin-bottom: 30px;
         margin-top: -10px;
        font-weight: 800;
        padding: 5px;

         span {

            //  width: 70px!important;
             left: 0;
         }
  }
     #timebox-end {
        position: absolute;
        width: auto;
        font-weight: 800;        
        right: 0%;
        top: -35px;
         padding: 5px;
        // left: 0;
        color: white;
        font-size: 30px;
        // left:45%!important;
         margin-left: 0;
         text-align: center;
         margin-bottom: 30px;
         margin-top: -10px;
        //    color: #1b1919;
        background: black;
        

         span {

            //  width: 70px!important;
             left: 0;
         }
  }
 .playing {
     color: #62aaa2!important;
     transition: all .4s ease-in;
     text-indent:10px;
     border-left: 9px solid #62aaa2;

     h2 {
            color: #62aaa2!important;
     }
 }

.series {
        margin: 0!important;
        padding: 0!important;
        padding-bottom: 30px!important;
        height: auto;
        position: relative;
        z-index: 9;
    .sec {

            
                li {
                list-style: none;
                position: relative;
                height: auto;
                background: white;
                width: 100%;
                cursor: pointer;

                .sub {
                    height: 90px;
                    width: 100%;
                    position: relative;
                    background: white;
                    
                    h2 {
                        position: absolute;
                        z-index: 2;
                        color: #222;
                        border-bottom: #d3d0d0 solid 1px;
                        left: 20px;
                        padding-bottom: 50px;
                        font-weight: 600;
                        font-size: 1.3vmax;
                        width: 98%;
                    transition: all .4s ease-in;
                        
                    }
                    p {
                        top: 70px;
                        z-index: 7;
                        left: 40px;
                        font-style: italic;
                        position: relative;
                    transition: all .4s ease-in;
                        
                    }
            
                }

         }
    }
        
}

  .icon {
            position: absolute;
            // left: 75%;
            right: 40px;
            top: 25px;
            background: transparent!important;
         i {
             margin-left: 40px;
             border: solid #222 2px;
             opacity: .6;
            //  margin: 10px;
             position: relative;
             padding: 10px 12px;
             font-size: 25px;
             border-radius: 50%;
             z-index: 99;
         }
         .fa-pause {
             color: white;
             background: #6bb5ac;
             border: solid #6bb5ac 2px;
             
         }
         }

.controls {
    position: fixed;
    background: rgba(34, 34, 34, 0.836);
    left:-0px;
    bottom: 0;
    z-index: 999;
    width: 100%;
    height: 80px;
    .main {
         position: relative;
            display: flex;
            justify-content: center;
            align-content: center;
            top:15px;
    }
            i {
            top: -30px;
            float: left;
            position: relative;
            display: flex;
            justify-content: center;
            align-content: center;
            margin: 15px;
            padding: 5px;
            color: #8cdacf;
            font-size: 40px;
            cursor: pointer;
        }
    .seek {
        // position: absolute;
        z-index: 9;
        top:-10px;
        
        input[type='range'] {
                -webkit-appearance: none !important;
                margin:0px;
                padding:0px;
                background: rgba(0, 0, 0, 0.637);
                color:white;
                border:none;
                height:13px;
                width: 100%;
            }    
            input[type='range']::-webkit-slider-thumb {
                -webkit-appearance: none !important;
                background: #528b84;
                height:20px;
                width:7px;
                // top: -3px;
                position: relative;
                // border: solid #222 2px;
                border-radius:5px;
                cursor:pointer;
            }
            input[type=range]::-webkit-slider-runnable-track {
              cursor: pointer;                
              background: transparent;
                border-radius: 1px;
                border: none;
                }
            input[type='range']::-ms-fill-lower  {
                background:#000;
            }
            input[type='range']::-ms-fill-upper  {
                background:#000;
            }
            input[type='range']::-moz-range-track {
                border:none;
                background: #000;
            }
        
            input[type='range']::-moz-range-thumb {
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:50px;
                cursor:pointer;
            }
            input[type='range']::-ms-thumb {
                -webkit-appearance: none !important;
                background: radial-gradient(#FFF, #333);
                height:11px;
 
                width:11px;
                cursor:pointer;                
                border-radius:50px;

            }
    }
}
.foot { background: black;}

@media screen and (max-width: 748px) {
    .intro {

    img {opacity: .6; height: 100%; width: auto; top: 0px;}
    .tab {
        width: 100%;
        height: 40px;
        h2 {
            font-size: 10px;
            color:#87d1c8;
            margin-left: 10px;
        }
    }
}

.search {
    height: 20px;
     input {
            position: relative;
            opacity: 1;
            font-size: 16px;
            top: -20px;
            left:25px;
            width: 80%;
           
            
        }
  
          i {
                top: -20px; 
                font-size: 30px; 
                left: 20px;
                
        }
}

.series {
    position: relative;
    overflow-x: hidden;
    height: 100vh;
    div {
        height: 100px;
        width: auto;
        position: relative;
        background: white;
       
        li {
        
         h2 {
            left: 20px;
            font-size: 1.2vmax;
         }
         p {
            top:30px;
            font-size: 8px;
         }
      
        }
    }
        
}
 .icon {
            position: absolute;
            left: 50%;
            top: -75px;
            width: 10px;
         i {
             margin-left: 10px;
             border: solid #222 2px;
             opacity: .6;
            //  margin: 10px;
             position: relative;
             padding: 10px 12px;
             font-size: 10px;
             border-radius: 50%;
         }
         }
  
}
</style>



