<template>
<div class="study">
    <!-- <div class="overlay"></div> -->
    <div class="main">
        <div class="download">
            <i class="fa fa-download"></i>
        </div>
        <div class="cover">
            <img src="../assets/overlay.png" alt="">
            <div class="info">
                <h1>Track Playing</h1>
                <h3>Como El</h3>
                <p>description of series</p>
            </div>
        </div>
        <div class="series">
            <div v-for="(serie, index) in searchList" :key="index">
                <li >
                    <img :src="serie.series_img" alt="">
                    <i v-if ="!serie.isActive" @click="toggleCardOn(serie);" class="fa fa-chevron-down" aria-hidden="true"></i>
                    <i v-if ="serie.isActive" @click="toggleOff(serie);" class="fa fa-chevron-up" aria-hidden="true"></i>
                    <h2>{{serie.series_name.replace(/-/g, " ")}}</h2>
                </li>

                   <li v-show="serie.isActive" class="collection-item" v-for="(audio, index) in serie.audio" :key="index" :id="audio.url" :value="audio.url"  > 
                            <a :href="audio" class="btn-floating waves-effect waves-light white" download><i class="material-icons">audiotrack</i></a><p class="truncate para" >| {{audio.name.replace(/.mp3/g, "")}}</p>
                    </li> 
            </div>
        </div>
        <div class="search">
            <i class="fa fa-search"></i>
            <input class="bar" type="text" v-model="search" name="search">
        </div>
        <div class="controls">
            <img src="../assets/overlay.png" alt="">             
            <!-- <div class="seek"><input id="seekslider" type="range" min="0" max="100" :value="value" step="1" @input="seeking"></div> -->
            <div class="seek"><input id="seekslider" type="range" min="0" max="100" :value="value" step="1" ></div>
            <div class="main">
                <i class="fa fa-backward" aria-hidden="true"></i>
                <i class="fa fa-play" aria-hidden="true"></i>
                <i class="fa fa-pause" v-if="pause" aria-hidden="true"></i>
                <i class="fa fa-forward" aria-hidden="true"></i>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import $ from 'jquery'
import axios from 'axios'
import firebase from 'firebase'
import {realDB} from  '../firebase/firebase'
import {s3} from  '../aws/aws-audio';

export default {
data(){
    return {
        pause: false,
        series2:[],
        search: '',
        series: [
            {img: require('../assets/comoel.jpg'), name: 'Como El'}, 
            {img: require('../assets/apocalipsis.jpg'), name: 'Apocalipsis'},
            {img: require('../assets/corintios.jpg'), name: 'Corintios'},
            {img: require('../assets/space.jpg'), name: 'Space'},
            ]
    }
},  
methods: {
       toggleOff(serie){
            serie.isActive = false;
        },

      toggleCardOn(serie){
          this.currentSerieSel = [];
          serie.isActive = true;

          for (var audio in serie.audio) {
                this.currentSerieSel.push(serie.audio[audio])
                }

    

      },
},
    computed:{
        // series(){
        //     return this.$store.state.audio.series
        // },
        searchList: function(){
            return this.series2.filter((serie) => {
                return serie.series_name.toLowerCase().match(this.search);
            })
        },
        sortList: function(){
            var audio = this.currentSerieSel;

            return audio.sort(function(a, b){
                    if(a.name < b.name) return -1;
                    if(a.name > b.name) return 1;
                    return 0;
        })
        },
    },
    created(){

           this.series2 = null;

          var arr = [];

            realDB.ref('series').on(('value'), function(snapshot){
                snapshot.forEach(function(child){
                    arr.push(child.val())
                })
               
            })
            this.series2 = arr;
            console.log(this.series2)
    //   this.$store.dispatch('getAudioData')
    },  
    mounted(){
    $('.fa-search').click(function(){
        $('.search').toggleClass('search-grow');
        $('.bar').toggleClass('show');
        $(this).toggleClass('grow')
    })
}

}
</script>

<style scoped lang="scss">
.study {
    position: relative;
    height: 100%;
    width: 100%;
    background: url('../assets/pattern.jpg');
    background-size: 100%;
    background-attachment: fixed;
    overflow: hidden;
    .overlay {
        height: 100%;
        width: 100%;
        position: absolute;
        // background: linear-gradient(to top, rgba(84, 179, 186, .9) 0%,rgba(22, 134, 131, .7) 100%);
        background:  linear-gradient(to top, rgba(29, 29, 29, 0.9) 0%,rgba(48, 48, 48, 0.7) 100%);
    }
    .main {
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
    top: 40px;


    }
    .download {
        box-shadow: -5px 15px 25px 0px rgba(0,0,0,0.4);
        background: linear-gradient(to bottom, rgb(52, 146, 153) 0%,rgba(22, 134, 131, .8) 100%);;
        position: absolute;
        height: 100px;
        width: 100px;
        top: 50px;
        z-index: 9;
        margin-left: -480px;
        transition: all .3s ease-in-out;
        i {
               top: 30px;
                color: white;
                font-size: 40px;
                position: relative;
                left: 30px;
                transition: all 1s ease-in-out;
                cursor: pointer;
        }
    }
    .cover, .series {
        height: 600px;
        width: 600px;
        position: absolute;
    }
    .cover {
        box-shadow: -15px 15px 35px 0px rgba(0,0,0,0.4);
        top: 80px;
        margin-left: -200px;
        background: red;
        background: url('../assets/comoel.jpg');
        background-size: cover;
        img {
            position: absolute;
            width: 100%;
            height: 100%;
            left: 0;
            // opacity: 27;
        }
        .info {
            top: 320px;
            position: absolute;
            left: 30%;
            color: white;

            h1 {
                font-weight: 600;
            }
        }
    }
    .series {
        box-shadow: 15px 15px 35px 0px rgba(0,0,0,0.4);
        overflow-y: scroll;
        max-height: 600px;
        background: black;
        top: 200px;
        margin-left: 300px;
        

        li {
            text-decoration: none;
            background-size: cover;
            position: relative;
            overflow: hidden;
            width: 100%;
            height: 150px;
                img {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    opacity: .6;
                }
                h2 {
                    color: white;
                    position: relative;
                    top: 10px;
                    font-size: 30px;
                    width: 500px;
                    left: 30px;
                }
                i {
                    position: absolute;
                    right: 20px;
                    font-size: 3em;
                    top:40px;
                    opacity: .8;
                    color: white;
                }
        }
    }
    .search {
                box-shadow: -5px 15px 25px 0px rgba(0,0,0,0.4);

        background: linear-gradient(to bottom, rgb(52, 146, 153) 0%,rgba(22, 134, 131, .8) 100%);;
        position: absolute;
        height: 100px;
        width: 100px;
        top: 90px;
        margin-left: 100px;
        transition: all .3s ease-in-out;
        input {
            position: relative;
            opacity: 0;
            font-size: 25px;
            color: white;
            font-family: 'Montserrat', sans-serif;
            font-weight: 200;
            top: 20px;
            left:40px;
            width: 75%;
            background: transparent;
            border: none;
            border-bottom: solid white 2px;
            transition: all .3s ease-in-out;
            
        }
        input[type=text] {
            color: white;
        }
        .show {
            opacity: 1;
        }

        i {
                top: 30px;
                color: white;
                font-size: 40px;
                position: relative;
                left: 30px;
                transition: all 1s ease-in-out;
                cursor: pointer;
                
        }
        .grow {
            transition: all 1s ease-in-out;
        }

    }
    .search-grow {
        transition: all .3s ease-in-out;
        width: 500px;
    }
    .controls {
        box-shadow: -5px 15px 35px 0px rgba(0,0,0,0.4);
        background: linear-gradient(to top, rgb(52, 146, 153) 0%,rgba(22, 134, 131, .9) 100%);
        position: absolute;
        height: 100px;
        width: 400px;
        top: 620px;
        margin-left: -230px;
        overflow: hidden;

        img {
            width: 150%;
            // height: 100%;
            opacity: .5;
            left: 0;
            position: absolute;
        }
        i {
            top: -30px;
            float: left;
            position: relative;
            display: flex;
            justify-content: center;
            align-content: center;
            margin: 15px;
            padding: 5px;
            color: white;
            font-size: 40px;
            cursor: pointer;
        }

    }

    #seekslider {
        width: 400px;
    }

    .seek {
        position: absolute;
        z-index: 9;
        top:-10px;
        
        input[type='range'] {
                -webkit-appearance: none !important;
                margin:0px;
                padding:0px;
                background: rgba(0, 0, 0, 0.637);
                color:white;
                border:none;
                height:13px;
            }    
            input[type='range']::-webkit-slider-thumb {
                -webkit-appearance: none !important;
                background: white;
                height:20px;
                width:15px;
                // top: -3px;
                position: relative;
                // border: solid #222 2px;
                border-radius:5px;
                cursor:pointer;
            }
            input[type=range]::-webkit-slider-runnable-track {
              cursor: pointer;                
              background: transparent;
                border-radius: 1px;
                border: none;
                }
            input[type='range']::-ms-fill-lower  {
                background:#000;
            }
            input[type='range']::-ms-fill-upper  {
                background:#000;
            }
            input[type='range']::-moz-range-track {
                border:none;
                background: #000;
            }
        
            input[type='range']::-moz-range-thumb {
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:50px;
                cursor:pointer;
            }
            input[type='range']::-ms-thumb {
                -webkit-appearance: none !important;
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                cursor:pointer;                
                border-radius:50px;

            }
    }
}

</style>



