<template>
    <div class="log">
        <img src="../assets/path.jpg" alt=""  data-aos="zoom-out" data-aos-duration="1000"> 
        <div class="main">
         <form>
                <div class="input-field">
                    <h2>Email:</h2>
                    <input id="email" type="email" class="validate" v-model="email">
                    </div>
                  <div class="input-field">
                    	<span class="btn-show-pass">
							<i class="fa fa-eye eye" v-if="eye" @click="eye = false"></i>
                            <i class="fa fa-eye-slash eye-slash hide" v-else @click="eye = true"></i>
                        </span>
                        <h2>Password:</h2>
                    <input id="password" type="password" class="validate" v-model="password">
                    </div>

                    <div class="btn" @click="getUser()"><span> <i class="fa fa-sign-in"></i> </span> </div>
               </form>

        </div>
    </div> 
</template>

<script>
import $ from 'jquery';

export default {
    data(){
        return {
            email: '',
            password: '',
            eye: true
        }
    },
      computed: {
      user () {
          return this.$store.getters.user
      },
       loading () {
        return this.$store.getters.loading
      }
  },
  watch: {
        user (value) {
            if (value !== null && value !== undefined) {
                // console.log(this.user)
                this.$router.push('/dashboard/'+ this.user.email);
            }
        }
  },
    methods:{
        getUser(){
      this.$store.dispatch('signUserIn', {email: this.email, password: this.password})
        }
    },
mounted(){
    $('.eye').click(function(){
        // console.log('clicked')
        var x = document.getElementById("password");

           if (x.type === "password") {
                x.type = "text";
                // $('.eye-slash')
            } else {
                x.type = "password";
            }

    })
}
}
</script>

<style lang="scss" scoped>
.log {
    // background: url('../assets/path.jpg');
    // background-size: cover;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    img {
        height: auto;
        width: 100%;
    }
    .main {
    top: 45vh;   
    position: absolute;
    left: 50%;
    transform: translate(-50%, -50%);
    
    }
        // top: 50%;
    form {
        position: relative;
        height: 100%;
  
        color:  rgb(95, 182, 189);
        .input-field {
           margin: 50px;
           h2 {
               font-weight: 600;
               font-family: brush;
               font-size: 50px;
           }
           input {
               background: none;
               border: none;
               width: 500px;
               border-bottom: 2px solid  rgb(95, 182, 189);
               color: rgb(255, 255, 255);
               font-size: 30px;
           }
           .btn-show-pass {
               position: absolute;
               bottom: 130px;
               right: 60px;
               i{
                   position: absolute;
                   bottom: 2px;
                   right: 2px;
               }
               .eye {
                   opacity: 1;
                   z-index: 1;
               }
               .eye-slash {
                   opacity: 1;
                   z-index: 0;
               }
           }
         
        }
          .btn {
            //    background: white;
               display: flex;
               justify-content: center;
               span {
                   background: white;
                   font-size: 30px;
                   padding: 20px;
                   height: 30px;
                   width: 30px;
                   border-radius: 50%;
                    display: flex;
                    justify-content: center;
                    transition: all .4s ease;
                    cursor: pointer;
                   
                    &:hover {
                        background: rgb(95, 182, 189);
                        transition: all .4s ease;
                        transform: scale(1.1);

                         i {
                        transition: all .4s ease;                        
                        color: white;
                    }
                    }
            
               }
           }
    }
}

@media only screen and (max-width: 800px) {
  .log {
    height: 100%!important;
    overflow: hidden!important;
    width: 100%;

        img {
        height: 100vh;
        width: auto;
    }
    .main {
    top: 45vh;   
    position: absolute;
    left: 50%;
    transform: translate(-50%, -50%);
    
    }
        // top: 50%;
    form {
        position: relative;
        height: 100%;
        width: 100vw;
        color:  rgb(95, 182, 189);
        .input-field {
           margin: 50px;
           h2 {
               font-weight: 600;
               font-family: brush;
               font-size: 30px;
           }
           input {
               background: none;
               border: none;
               width: 100%;
               border-bottom: 2px solid  rgb(95, 182, 189);
               color: rgb(255, 255, 255);
               font-size: 30px;
           }
           .btn-show-pass {
               position: absolute;
               bottom: 130px;
               right: 60px;
               i{
                   position: absolute;
                   bottom: 2px;
                   right: 2px;
               }
               .eye {
                   opacity: 1;
                   z-index: 1;
               }
               .eye-slash {
                   opacity: 1;
                   z-index: 0;
               }
           }
         
        }
          .btn {
            //    background: white;
               display: flex;
               justify-content: center;
               span {
                   background: white;
                   font-size: 30px;
                   padding: 20px;
                   height: 20px;
                   width: 20px;
                   border-radius: 50%;
                    display: flex;
                    justify-content: center;
                    transition: all .4s ease;
                    cursor: pointer;
                   
                    &:hover {
                        background: rgb(95, 182, 189);
                        transition: all .4s ease;
                        transform: scale(1.1);

                         i {
                        transition: all .4s ease;                        
                        color: white;
                    }
                    }
                            i {
                        font-size: 20px!important;
                    }
               }
           }
    }
}
}
</style>



