<template>
    <div>
        <h1>hello</h1>
        <li @click="logout()" ><i class="fa fa-sign-out fa-2x" style="color:white" aria-hidden="true" ></i></li>               

    </div>
</template>

<script>
export default {
    computed: {
      user(){
          return this.$store.state.user.user
      }
  },
  watch: {
        user: function(val){
            val = this.$store.state.user.user
            }  
    },
  methods:{
      logout(){

          this.$store.dispatch('logout')

      }
    }
}
</script>

<style lang="scss" scoped>


</style>



