import firebase from 'firebase'
import db from  '../../firebase/firebase'
import router from '../../router'
import createPersistedState from 'vuex-persistedstate'


export default {
    state: {
        hymnsData: [
            {
              id: 1,
              name: 'Cristo',
              url: 'https://drive.google.com/file/d/138b7XG1U4-nNxDQckUMLBbDlrkkKG8Tk/preview'
            },
            {
                id: 2,
                name: 'Jesus',
                url: 'https://drive.google.com/file/d/1XW_k7-p8SYu8NUsWuz_8iMexE9igCWWh/preview'
                
            },
            {
                id: 3,
                name: 'Amen',
                url: 'https://drive.google.com/file/d/1Hdg_yrUepRiHHWOzbldIiTr2jXF2-LO_/preview'
            }
          ],
          favoriteList: [],
          user: null,
          searchText: '',
          loading: false,
          error: null
    },
    plugins: [createPersistedState()],
    mutations: {
          setUser (state, payload) {
            state.user = payload
          },
          setLoading (state, payload) {
            state.loading = payload
          },
          setError (state, payload) {
            state.error = payload
          },
          clearError (state) {
            state.error = null
          },
          hymnsData (state, payload) {
            state.hymnsData = payload
          },
          searchText (state, payload) {
            state.searchText = payload.search
          },
          favList (state, payload) {
            state.favoriteList = payload
          }
    },
    actions: {
      snackBar({commit}, payload){
        $(payload.class).addClass('show');
        setTimeout(function(){ $(payload.class).removeClass('show')}, payload.timeout);
      },
        fetchUserData ({commit, getters}, payload) {
            commit('setLoading', true)

            db.collection("Users").doc(payload).get().then(doc => {
                const data = doc.data();

                // console.log(data)

                commit('setLoading', false)
                commit('setUser', data)
                commit('favList', data.data)
                
            }) .catch(
                (error) => {
                    console.log(error)
                    commit('setLoading', false)
                }
            )   
        },
        signUserUp ({commit, dispatch}, payload) {
            commit('setLoading', true)
            commit('clearError')
            console.log(payload)
            firebase.auth().createUserWithEmailAndPassword(payload.email, payload.password)
            .then(
                user => {
                commit('setLoading', false)
                db.collection('Users').doc(payload.email).set({
                      firstName: payload.firstName,
                      lastName: payload.lastName,
                      dashboard: false,
                      email: payload.email,
                      password: payload.password,
                      data: []
                })
                const data = {
                  firstName: payload.firstName,
                      lastName: payload.lastName,
                      dashboard: false,
                      email: payload.email,
                      password: payload.password,
                      data: []
                }
                commit('setUser', data)

                }
            )
            .catch(
                error => {
                commit('setLoading', false)
                commit('setError', error)
                console.log(error)
                }
            )
        },
        signUserIn ({commit, dispatch}, payload) {
            commit('setLoading', true)
            commit('clearError')
             firebase.auth().signInWithEmailAndPassword(payload.email, payload.password)
            .then(
                user => {
                commit('setLoading', false)
                // console.log(user)
                const newUser = {
                    id: user.uid,
                    email: payload.email
                }
                dispatch('fetchUserData', payload.email)
                // console.log(newUser)
                }
            )
            .catch(
                error => {
                commit('setLoading', false)
                commit('setError', error)
                console.log(error)
                }
            )
        },
        logout ({commit}) {
          firebase.auth().signOut()
          router.push('/miembros')
          commit('setUser', null)
        },
        clearError ({commit}) {
          commit('clearError')
        },
        addToFav({commit, dispatch, state}, payload){

            payload['active'] = true;
  
            commit('setLoading', true)
            var arr = state.user;
  
            arr.data.push(payload)
    
            db.collection("Users").doc(state.user.email).set({
              dashboard: arr.dashboard,
              data: arr.data,
              email: arr.email,
              firstName: arr.firstName,
              lastName: arr.lastName,
              password: arr.password
  
            }).then(() => {
              commit('setLoading', false)
              commit('favList', arr.data)
  
              dispatch('snackBar', {timeout: 3000, class: '.add'})            
  
            }).catch(
                (error) => {
                    console.log(error)
                    commit('setLoading', false)
                }
            )  
          },
          deleteFav({commit, dispatch, state}, payload){
            commit('setLoading', true)
  
            var newHymns = state.hymnsData.filter((item) => {
                return item.id !== payload.id
            })
          
            var newFav = state.favoriteList.filter((item) => {
              return item.id !== payload.id
            })
  
            payload.active = false;
  
            newHymns.push(payload)
          
            var arr = state.user;
            arr.data = newFav;
  
            db.collection("Users").doc(state.user.email).set({
              dashboard: arr.dashboard,
              data: arr.data,
              email: arr.email,
              firstName: arr.firstName,
              lastName: arr.lastName,
              password: arr.password
  
            }).then(() => {
              console.log('added to fav')
              commit('setLoading', false)
              commit('favList', arr.data)
              commit('hymnsData', newHymns)
              dispatch('snackBar', {timeout: 3000, class: '.remove'})            
  
  
            }).catch(
                (error) => {
                    console.log(error)
                    commit('setLoading', false)
                }
            )  
  
          }

    },
    getters: {
        searchHymn (state, getters) {
            if (state.searchText == '') {
                return getters.loadHymnData
            } else {
              return state.hymnsData.filter((hymn) => {
                   return hymn.name.toLowerCase().match(state.searchText) || hymn.id.toString().match(state.searchText);
                 })
            }
          },
          loadHymnData (state) {
            return state.hymnsData.sort((hymnA, hymnB) => {
              return hymnA.id > hymnB.id
            })
          },
          loadHymn (state) {
            return (hymnId) => {
              // console.log(hymnId)
              return state.hymnsData.find((hymn) => {
                return hymn.id == hymnId
              })
            }
          },
          favList (state) {
            if(state.favoriteList == null || state.favoriteList == undefined) {
              return state.favoriteList
            } else {
              return state.favoriteList.sort((hymnA, hymnB) => {
                return hymnA.id > hymnB.id
              })
            }
          },
          user (state) {
            return state.user
          },
          loading (state) {
            return state.loading
          },
          error (state) {
            return state.error
          }
    }
}


